diff --git a/pkg/bloom/bloom_test.go b/pkg/bloom/bloom_test.go
--- a/pkg/bloom/bloom_test.go
+++ b/pkg/bloom/bloom_test.go
@@
 	for i := 50; i < 100; i++ {
 		if !cf.Contains([]byte(fmt.Sprintf("cfnv-%d", i))) {
 			t.Fatalf("should still contain cfnv-%d", i)
 		}
 	}
 }
+
+// TestCountingFilter_NoFalseNegativeUnderChurn exercises the saturation bug:
+// a tiny filter is hammered with interleaved add/remove churn that drives
+// shared counters to saturation, after which a still-present element must
+// never test absent.
+func TestCountingFilter_NoFalseNegativeUnderChurn(t *testing.T) {
+	cf := NewCountingFilter(8, 0.5) // tiny: ~12 bits, forces collisions/saturation
+	cf.Add([]byte("keep"))
+	cf.Add([]byte("keep"))
+	for i := 0; i < 5000; i++ {
+		item := []byte(fmt.Sprintf("churn-%d", i))
+		cf.Add(item)
+		cf.Remove(item)
+		if !cf.Contains([]byte("keep")) {
+			t.Fatalf("false negative for kept element after %d churn ops", i)
+		}
+	}
+}
+
+// TestCountingFilter_RepeatedAddPartialRemove confirms an element added more
+// times than removed always tests present.
+func TestCountingFilter_RepeatedAddPartialRemove(t *testing.T) {
+	cf := NewCountingFilter(1000, 0.01)
+	for i := 0; i < 5; i++ {
+		cf.Add([]byte("x"))
+	}
+	for i := 0; i < 3; i++ {
+		if !cf.Remove([]byte("x")) {
+			t.Fatal("remove should succeed")
+		}
+		if !cf.Contains([]byte("x")) {
+			t.Fatalf("element must remain present after %d of 5 removes", i+1)
+		}
+	}
+}
+
+// TestFilter_FillRatioMatchesFullScan asserts the O(1) FillRatio equals a
+// full bit scan across additions, unions, and resets.
+func TestFilter_FillRatioMatchesFullScan(t *testing.T) {
+	f := NewFilterRaw(1024, 7)
+	check := func(label string) {
+		set := 0
+		for _, w := range f.bits {
+			for w != 0 {
+				set++
+				w &= w - 1
+			}
+		}
+		want := float64(set) / float64(f.size)
+		if got := f.FillRatio(); got != want {
+			t.Fatalf("%s: FillRatio mismatch got %v want %v", label, got, want)
+		}
+	}
+	check("empty")
+	for i := 0; i < 200; i++ {
+		f.Add([]byte(fmt.Sprintf("item-%d", i)))
+		check(fmt.Sprintf("after add %d", i))
+	}
+	g := NewFilterRaw(1024, 7)
+	for i := 0; i < 50; i++ {
+		g.Add([]byte(fmt.Sprintf("other-%d", i)))
+	}
+	if !f.Union(g) {
+		t.Fatal("union should succeed")
+	}
+	check("after union")
+	f.Reset()
+	check("after reset")
+}

