+
+// TestCountingFilter_NoFalseNegativeUnderChurn drives heavy interleaved churn so
+// that the kept element's counter positions saturate. On the broken base the
+// saturated counters get decremented back to zero during the removals, producing
+// a false negative.
+func TestCountingFilter_NoFalseNegativeUnderChurn(t *testing.T) {
+	cf := NewCountingFilter(50, 0.01)
+	cf.Add([]byte("keep"))
+	for i := 0; i < 2000; i++ {
+		cf.Add([]byte(fmt.Sprintf("churn-%d", i)))
+	}
+	for i := 0; i < 2000; i++ {
+		cf.Remove([]byte(fmt.Sprintf("churn-%d", i)))
+	}
+	if !cf.Contains([]byte("keep")) {
+		t.Fatal("false negative: kept element reported absent after churn")
+	}
+}
+
+// TestCountingFilter_RepeatedAddPartialRemove confirms an element added more
+// times than it is removed always tests present.
+func TestCountingFilter_RepeatedAddPartialRemove(t *testing.T) {
+	cf := NewCountingFilter(1000, 0.01)
+	cf.Add([]byte("x"))
+	cf.Add([]byte("x"))
+	cf.Add([]byte("x"))
+	cf.Remove([]byte("x"))
+	cf.Remove([]byte("x"))
+	if !cf.Contains([]byte("x")) {
+		t.Fatal("element added more times than removed must remain present")
+	}
+}
+
+func scanFillRatio(f *Filter) float64 {
+	set := 0
+	for _, word := range f.bits {
+		for word != 0 {
+			set++
+			word &= word - 1
+		}
+	}
+	return float64(set) / float64(f.Size())
+}
+
+// TestFilter_FillRatioMatchesScan checks FillRatio equals a full-scan
+// computation after additions, a union, and a reset.
+func TestFilter_FillRatioMatchesScan(t *testing.T) {
+	f := NewFilterRaw(1024, 7)
+	for i := 0; i < 100; i++ {
+		f.Add([]byte(fmt.Sprintf("a-%d", i)))
+	}
+	if got, want := f.FillRatio(), scanFillRatio(f); got != want {
+		t.Fatalf("after adds FillRatio %v != scan %v", got, want)
+	}
+	g := NewFilterRaw(1024, 7)
+	for i := 0; i < 50; i++ {
+		g.Add([]byte(fmt.Sprintf("b-%d", i)))
+	}
+	f.Union(g)
+	if got, want := f.FillRatio(), scanFillRatio(f); got != want {
+		t.Fatalf("after union FillRatio %v != scan %v", got, want)
+	}
+	f.Reset()
+	if got, want := f.FillRatio(), scanFillRatio(f); got != want {
+		t.Fatalf("after reset FillRatio %v != scan %v", got, want)
+	}
+}

